# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(initial_balances, transactions):
    """
    Processes financial transactions and updates account balances.

    Args:
        initial_balances (dict): A dictionary where keys are account IDs (str)
                                 and values are their initial balances (float).
                                 Example: {'ACC001': 1000.0, 'ACC002': 500.0}
        transactions (list): A list of transaction dictionaries. Each transaction
                             dictionary should have the following keys:
                             - 'transaction_id' (str): Unique ID for the transaction.
                             - 'type' (str): 'deposit' or 'withdrawal'.
                             - 'account_id' (str): The account ID affected by the transaction.
                             - 'amount' (float): The amount of the transaction.

                             Example: [
                                 {'transaction_id': 'TXN001', 'type': 'deposit', 'account_id': 'ACC001', 'amount': 200.0},
                                 {'transaction_id': 'TXN002', 'type': 'withdrawal', 'account_id': 'ACC002', 'amount': 50.0}
                             ]

    Returns:
        dict: A dictionary where keys are account IDs (str) and values are their
              updated balances (float) after processing all transactions.
              If an account ID in a transaction does not exist in initial_balances,
              it will be created with an initial balance of 0 before applying the transaction.
    """
    current_balances = initial_balances.copy()

    for transaction in transactions:
        transaction_type = transaction['type']
        account_id = transaction['account_id']
        amount = transaction['amount']

        if account_id not in current_balances:
            current_balances[account_id] = 0.0  # Initialize new account if it doesn't exist

        if transaction_type == 'deposit':
            current_balances[account_id] += amount
        elif transaction_type == 'withdrawal':
            # Optional: Add overdraft protection here if needed
            # For simplicity, we allow withdrawals to go negative
            current_balances[account_id] -= amount
        else:
            # You might want to log or raise an error for unknown transaction types
            print(f"Warning: Unknown transaction type '{transaction_type}' for transaction ID '{transaction['transaction_id']}'. Skipping.")

    return current_balances